# backend/routes/ws.py
import asyncio, json
from fastapi import APIRouter, WebSocket, WebSocketDisconnect, Query, HTTPException
from anthropic import AsyncAnthropic, APIStatusError

from .auth import decode_token

router = APIRouter()
client = AsyncAnthropic()

# ── Connection manager: track active WebSockets per user ──────────────────
class ConnectionManager:
    def __init__(self):
        self._conns: dict[str, set[WebSocket]] = {}

    async def connect(self, user_id: str, ws: WebSocket):
        await ws.accept()
        self._conns.setdefault(user_id, set()).add(ws)

    def disconnect(self, user_id: str, ws: WebSocket):
        self._conns.get(user_id, set()).discard(ws)

    async def broadcast_user(self, user_id: str, data: dict):
        for ws in list(self._conns.get(user_id, [])):
            try:
                await ws.send_json(data)
            except Exception:
                pass

manager = ConnectionManager()

# ── WebSocket endpoint ─────────────────────────────────────────────────────
@router.websocket("/ws")
async def websocket_endpoint(
    ws: WebSocket,
    token: str = Query(...),   # JWT in query param (headers not available post-handshake)
):
    try:
        user = decode_token(token)
    except Exception:
        await ws.close(code=1008, reason="Invalid token")
        return

    await manager.connect(user.id, ws)
    active_task: asyncio.Task | None = None

    try:
        while True:
            data = await ws.receive_json()
            msg_type = data.get("type")

            if msg_type == "chat":
                if active_task and not active_task.done():
                    active_task.cancel()
                active_task = asyncio.create_task(
                    _stream_llm(ws, data["messages"], data.get("model", "claude-3-5-haiku-20241022"))
                )

            elif msg_type == "cancel":
                if active_task and not active_task.done():
                    active_task.cancel()
                await ws.send_json({"type": "cancelled"})

            elif msg_type == "ping":
                await ws.send_json({"type": "pong"})

    except WebSocketDisconnect:
        pass
    finally:
        if active_task and not active_task.done():
            active_task.cancel()
        manager.disconnect(user.id, ws)

async def _stream_llm(ws: WebSocket, messages: list, model: str):
    """Stream LLM tokens to the WebSocket."""
    try:
        async with client.messages.stream(
            model=model,
            max_tokens=2048,
            messages=messages,
        ) as stream:
            async for text_delta in stream.text_stream:
                await ws.send_json({"type": "delta", "text": text_delta})

            usage = (await stream.get_final_message()).usage
            await ws.send_json({
                "type": "done",
                "usage": {
                    "input_tokens": usage.input_tokens,
                    "output_tokens": usage.output_tokens,
                },
            })

    except asyncio.CancelledError:
        await ws.send_json({"type": "cancelled"})
    except APIStatusError as exc:
        await ws.send_json({
            "type": "error",
            "code": "rate_limit" if exc.status_code == 429 else "api_error",
            "message": str(exc.message),
        })
    except Exception:
        await ws.send_json({"type": "error", "code": "server_error", "message": "Internal error"})

// hooks/useWebSocket.ts
import { useCallback, useEffect, useRef, useState } from "react";

type WsMessage = { type: string; [key: string]: unknown };
type Handler = (msg: WsMessage) => void;

export function useWebSocket(url: string) {
  const wsRef = useRef<WebSocket | null>(null);
  const retryRef = useRef(0);
  const handlersRef = useRef<Map<string, Handler>>(new Map());
  const [connected, setConnected] = useState(false);

  const connect = useCallback(() => {
    const ws = new WebSocket(url);

    ws.onopen = () => {
      setConnected(true);
      retryRef.current = 0;
    };

    ws.onmessage = (event) => {
      const msg: WsMessage = JSON.parse(event.data);
      handlersRef.current.get(msg.type)?.(msg);
      handlersRef.current.get("*")?.(msg);   // wildcard handler
    };

    ws.onclose = (event) => {
      setConnected(false);
      wsRef.current = null;

      // Only reconnect on abnormal closure
      if (event.code !== 1000) {
        const delay = Math.min(1000 * 2 ** retryRef.current, 30_000);
        retryRef.current += 1;
        setTimeout(connect, delay);
      }
    };

    ws.onerror = () => {
      ws.close();
    };

    wsRef.current = ws;
  }, [url]);

  useEffect(() => {
    connect();
    return () => {
      wsRef.current?.close(1000, "component unmounted");
    };
  }, [connect]);

  // Register a handler for a message type
  const on = useCallback((type: string, handler: Handler) => {
    handlersRef.current.set(type, handler);
    return () => handlersRef.current.delete(type);
  }, []);

  const send = useCallback((msg: WsMessage) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify(msg));
    }
  }, []);

  return { connected, send, on };
}

// components/WsChat.tsx
import { useEffect, useState } from "react";
import { useWebSocket } from "../hooks/useWebSocket";

export function WsChat({ token }: { token: string }) {
  const { connected, send, on } = useWebSocket(
    `wss://api.example.com/ws?token=${token}`
  );
  const [messages, setMessages] = useState<{ role: string; content: string }[]>([]);
  const [streaming, setStreaming] = useState(false);
  const pendingRef = useRef("");

  useEffect(() => {
    const offDelta = on("delta", (msg) => {
      pendingRef.current += msg.text as string;
      setMessages(prev => {
        const next = [...prev];
        const last = next[next.length - 1];
        if (last?.role === "assistant") {
          next[next.length - 1] = { ...last, content: pendingRef.current };
        } else {
          next.push({ role: "assistant", content: pendingRef.current });
        }
        return next;
      });
    });

    const offDone = on("done", () => {
      setStreaming(false);
      pendingRef.current = "";
    });

    const offCancelled = on("cancelled", () => {
      setStreaming(false);
      pendingRef.current = "";
    });

    return () => { offDelta(); offDone(); offCancelled(); };
  }, [on]);

  const submit = (userText: string) => {
    const userMsg = { role: "user", content: userText };
    setMessages(prev => [...prev, userMsg]);
    setStreaming(true);
    pendingRef.current = "";
    send({ type: "chat", messages: [...messages, userMsg] });
  };

  const cancel = () => {
    send({ type: "cancel" });
  };

  return (
    <div>
      {/* message list, input bar, Stop button when streaming */}
    </div>
  );
}

# First-message auth pattern
@router.websocket("/ws")
async def websocket_auth_first_message(ws: WebSocket):
    await ws.accept()   # accept first to allow the client to send auth
    try:
        auth_data = await asyncio.wait_for(ws.receive_json(), timeout=5.0)
    except asyncio.TimeoutError:
        await ws.close(code=1008, reason="Auth timeout")
        return

    if auth_data.get("type") != "auth":
        await ws.close(code=1008, reason="Expected auth message")
        return

    try:
        user = decode_token(auth_data["token"])
    except Exception:
        await ws.close(code=1008, reason="Invalid token")
        return

    # Now enter normal message loop with authenticated user
    await _handle_session(ws, user)

// Client-side heartbeat
function startHeartbeat(ws: WebSocket): ReturnType<typeof setInterval> {
  return setInterval(() => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({ type: "ping" }));
    }
  }, 25_000);   // 25s keeps most load balancer timeouts at bay
}

